def main(value, value_2):
    print(-value ** value_2)

if __name__ == "__main__":
    value = 3

    value_2 = 2
    main(value, value_2)

def main(value, value_2):
    print(not value or value_2)

if __name__ == "__main__":
    value = True

    value_2 = False
    main(value, value_2)

def main(value, value_2):
    print(value == (not value_2))

if __name__ == "__main__":
    value = True

    value_2 = False
    main(value, value_2)

def main(value, value_2):
    print(~value + value_2)

if __name__ == "__main__":
    value = 4

    value_2 = 3
    main(value, value_2)
